package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalPriveRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.BasisRszVerdelerOptions;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.AbstractSectoraalPensioenFonds;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenresultaat.service.util.RekenresultaatBedrag;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.rsz.dmfa.KengetalDmfa;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

public class BijdrageSectoraalPensioenfondsArbeiders extends AbstractSectoraalPensioenFonds {
    public static final MoneyKey MONEY_KEY_INHOUDING = RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_SECTORAAL_PENSIOENFONDS_ARBEIDERS_KEY;

    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_BASIS = RekenresultaatBedrag.BASIS_SECTORAAL_PENSIOENFONDS_ARBEIDERS;
    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_INHOUDING = RekenresultaatBedrag.PATRONALE_BIJDRAGE_SEC_PENS_ARB;

    public static final int BIJDRAGE_NIET_VAN_TOEPASSING = 9;

    private final BijdrageSectoraalPensioenfondsArbeidersOptions options;

    public BijdrageSectoraalPensioenfondsArbeiders(RszConstantService rszConstantService, ConstantManager constantManager, RekenTijd rekenTijd) {
        super(rszConstantService, constantManager);

        boolean isSectoraalPensioenfondsArbeidersRekenen = isSectoraalPensioenfondsArbeidersRekenen(constantManager, rekenTijd);
        this.options = new BijdrageSectoraalPensioenfondsArbeidersOptions(isSectoraalPensioenfondsArbeidersRekenen);
    }

    public static boolean isSectoraalPensioenfondsArbeidersRekenen(ConstantManager constantManager, RekenTijd rekenTijd) {
        Constant sectoraalPensioenfondsArbeidersConstante = constantManager.getActualConstant(Konstanten.CST_SECTORAAL_PENSIOENFONDS_ARBEIDERS, rekenTijd);
        return sectoraalPensioenfondsArbeidersConstante == null || !sectoraalPensioenfondsArbeidersConstante.getInteger().equals(BIJDRAGE_NIET_VAN_TOEPASSING);
    }

    public static void setOnLoonElement(LoonElement loonElement, Money bedrag, BasisRszVerdelerOptions options) {
        if (options.isSectoraalPensioenfondsArbeiders()) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_SECTORAAL_PENSIOENFONDS_ARBEIDERS_KEY, bedrag);
        }
    }

    @Override
    public BigDecimal getPercentage(SleutelGegevens gegevens, LocalDate zoekDatum) {
        KengetalDmfa kengetalDmfa = makeKengetalDmfa(gegevens);
        Integer typeLeerling = gegevens.getTypeLeerling();
        if (options.isSectoraalPensioenfondsArbeidersRekenen() && kengetalDmfa.isFondsArbeiders() && typeLeerling != null && typeLeerling == 0) {
            return getPercentageBijdrageSectoraalPensioenfonds(gegevens, zoekDatum, DmfapplWnkengetal.SECTORAAL_PENSIOENFONDS_ARBEIDERS);
        } else {
            return BigDecimal.ZERO;
        }
    }
}
